final:
module TrapDetect(
    input  Trap,
    input  TrapCond,
    input  [31:0] ALUResult,
    output EXC_Tr
    );
    wire ALUZero = (ALUResult == 32'h00000000);
  wire temp1_Trap = Trap;
  wire temp2_(TrapCond ^ ALUZero) = (TrapCond ^ ALUZero);
  assign EXC_Tr = temp1_Trap & temp2_(TrapCond ^ ALUZero);
endmodule
